import React, { useEffect, useState } from 'react';
import { Pie, Bar, Line, Scatter } from 'react-chartjs-2';
import axios from 'axios';
import './Reports.css';

import {
  Chart as ChartJS,
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend
);

const chartStyle = {
  maxWidth: 500,
  maxHeight: 350,
  margin: '0 auto',
};

const Reports = () => {
  const [categoryData, setCategoryData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchCategoryData() {
      try {
        const response = await axios.get('http://localhost:8000/api/category-data');
        setCategoryData(response.data.category_distribution);
      } catch (error) {
        setCategoryData(null);
      } finally {
        setLoading(false);
      }
    }
    fetchCategoryData();
  }, []);

  // Prepare chart data from API
  const pieChartData = categoryData
    ? {
        labels: Object.keys(categoryData),
        datasets: [
          {
            label: 'Category Distribution',
            data: Object.values(categoryData),
            backgroundColor: [
              '#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0', '#9966FF', '#FF9F40', '#C9CBCF', '#BDB76B', '#8FBC8F', '#E9967A'
            ],
          },
        ],
      }
    : {
        labels: ['Sample A', 'Sample B', 'Sample C'],
        datasets: [
          {
            label: 'Sample Data',
            data: [10, 20, 30],
            backgroundColor: ['#FF6384', '#36A2EB', '#FFCE56'],
          },
        ],
      };

  const defaultOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Category Distribution',
      },
    },
    maintainAspectRatio: false,
  };

  return (
    <div className="reports-container">
      <h1>Reports Dashboard</h1>

      <div className="report-section">
        <h2>1️⃣ Category Distribution</h2>
        <div style={chartStyle}>
          {loading ? (
            <p>Loading...</p>
          ) : (
            <Pie data={pieChartData} options={defaultOptions} height={350} width={500} />
          )}
        </div>
      </div>

      {/* ...existing code for other charts... */}
    </div>
  );
};

export default Reports;
